// Parse classification result from LLM
const items = [];

for (const item of $input.all()) {
  const llmResponse = item.json;
  const originalData = $('Load PBC Checklist').item.json;

  let classification;
  try {
    const content = llmResponse.choices[0].message.content;
    if (typeof content === 'string') {
      const cleaned = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
      classification = JSON.parse(cleaned);
    } else {
      classification = content;
    }
  } catch (e) {
    classification = {
      classifications: [],
      primary_classification: null,
      summary: 'Classification parse error: ' + e.message
    };
  }

  // Build tag list from matched PBC items
  const tags = [];
  if (classification.classifications && classification.classifications.length > 0) {
    for (const match of classification.classifications) {
      tags.push(match.pbc_item_id);
      // Also add category-level tag
      const checklistItem = originalData.pbcChecklist.find(c => c.id === match.pbc_item_id);
      if (checklistItem && !tags.includes('pbc-' + checklistItem.category.toLowerCase().replace(/[^a-z0-9]/g, '-'))) {
        tags.push('pbc-' + checklistItem.category.toLowerCase().replace(/[^a-z0-9]/g, '-'));
      }
    }
  }
  tags.push('pbc-classified');

  // Determine primary match name
  let primaryName = 'Unclassified';
  if (classification.primary_classification) {
    const primary = originalData.pbcChecklist.find(c => c.id === classification.primary_classification);
    primaryName = primary ? primary.item : classification.primary_classification;
  }

  items.push({
    json: {
      documentId: originalData.document.id,
      documentTitle: originalData.document.title,
      filename: originalData.document.filename,
      primaryClassification: classification.primary_classification,
      primaryName,
      classifications: classification.classifications || [],
      summary: classification.summary || '',
      tags,
      confidence: classification.classifications && classification.classifications.length > 0
        ? Math.max(...classification.classifications.map(c => c.confidence))
        : 0
    }
  });
}

return items;

// Compare received documents against full PBC checklist to identify gaps
const pbcChecklist = [
  { id: "PBC-001", item: "Trial Balance", category: "Financial Data" },
  { id: "PBC-002", item: "General Ledger detail", category: "Financial Data" },
  { id: "PBC-003", item: "Tax returns (prior year Federal + State)", category: "Tax Returns" },
  { id: "PBC-004", item: "Financial statements", category: "Financial Data" },
  { id: "PBC-005", item: "Fixed asset register", category: "Assets" },
  { id: "PBC-006", item: "Lease schedules", category: "Assets" },
  { id: "PBC-007", item: "Stock compensation details", category: "Compensation" },
  { id: "PBC-008", item: "Intercompany transactions", category: "Intercompany" },
  { id: "PBC-009", item: "Permanent/temporary difference support", category: "Tax Provision" },
  { id: "PBC-010", item: "Tax provision workpapers", category: "Tax Provision" },
  { id: "PBC-011", item: "Deferred tax roll-forward", category: "Tax Provision" },
  { id: "PBC-012", item: "Uncertain tax positions (FIN 48/ASC 740-10)", category: "Tax Provision" },
  { id: "PBC-013", item: "State apportionment schedules", category: "State Tax" },
  { id: "PBC-014", item: "R&D credit support", category: "Credits" },
  { id: "PBC-015", item: "Entity org chart", category: "Entity Structure" }
];

const documents = $input.first().json;
const results = documents.results || documents.data || [];

// Extract PBC item IDs from document tags
const receivedPbcIds = new Set();
const documentsByPbc = {};

for (const doc of results) {
  const tags = doc.tags || [];
  for (const tag of tags) {
    const tagName = typeof tag === 'string' ? tag : (tag.name || tag.slug || '');
    if (tagName.startsWith('PBC-')) {
      receivedPbcIds.add(tagName);
      if (!documentsByPbc[tagName]) documentsByPbc[tagName] = [];
      documentsByPbc[tagName].push({
        id: doc.id,
        title: doc.title || doc.original_filename || 'Untitled',
        created: doc.created || doc.created_date
      });
    }
  }
}

// Identify received items and gaps
const received = [];
const gaps = [];

for (const item of pbcChecklist) {
  if (receivedPbcIds.has(item.id)) {
    received.push({
      ...item,
      status: 'received',
      documents: documentsByPbc[item.id] || []
    });
  } else {
    gaps.push({
      ...item,
      status: 'missing'
    });
  }
}

// Group gaps by category
const gapsByCategory = {};
for (const gap of gaps) {
  if (!gapsByCategory[gap.category]) gapsByCategory[gap.category] = [];
  gapsByCategory[gap.category].push(gap);
}

const totalItems = pbcChecklist.length;
const receivedCount = received.length;
const gapCount = gaps.length;
const completionPct = Math.round((receivedCount / totalItems) * 100);

return [{
  json: {
    totalItems,
    receivedCount,
    gapCount,
    completionPct,
    received,
    gaps,
    gapsByCategory,
    analysisDate: new Date().toISOString()
  }
}];

